<template>
  <div id="login">
    <img src="../assets/img/logo.png"
         alt="">
    <a-form id="components-form-demo-normal-login"
            :form="form"
            class="login-form"
            @submit="handleSubmit">
      <a-form-item>
        <a-input size="large"
                 v-decorator="[
          'username',
          { rules: [{ required: true, message: 'Please input your username!' }] }
        ]"
                 placeholder="Username">
          <a-icon slot="prefix"
                  type="user"
                  style="color: rgba(0,0,0,.25)" />
        </a-input>
      </a-form-item>
      <a-form-item>
        <a-input size="large"
                 v-decorator="[
          'password',
          { rules: [{ required: true, message: 'Please input your Password!' }] }
        ]"
                 type="password"
                 placeholder="Password">
          <a-icon slot="prefix"
                  type="lock"
                  style="color: rgba(0,0,0,.25)" />
        </a-input>
      </a-form-item>
      <a-form-item>
        <a-button size="large"
                  type="primary"
                  html-type="submit"
                  class="login-form-button">
          登 陆
        </a-button>
      </a-form-item>
    </a-form>
    <router-link to="/reg">注册用户</router-link>
  </div>
</template>
<style lang="less" scoped>
#login {
  width: 500px;
  min-height: 400px;
  padding: 20px;
  // background: #eaeaea;
  margin: 50px auto;
  border-radius: 8px;
  img {
    display: block;
    margin: 0 auto 50px auto;
  }
}
#components-form-demo-normal-login .login-form {
  max-width: 300px;
}
#components-form-demo-normal-login .login-form-forgot {
  float: right;
}
#components-form-demo-normal-login .login-form-button {
  width: 100%;
}
</style>
<script>
export default {
  beforeCreate () {
    this.form = this.$form.createForm(this);
  },
  methods: {
    handleSubmit (e) {
      e.preventDefault();
      this.form.validateFields((err, values) => {
        if (!err) {
          var data = {};
          data['username'] = values.username;
          data["password"] = values.password;
          this.$ajax.post(this.baseurl + "login", this.$qs.stringify(data)).then((res) => {
            if (res.status == 200 && res.data.code == 200) {
              // console.log(res);
              // vuex 调用actions里面的setUser方法
              this.$store.dispatch("setUser", true)
              this.$store.dispatch("setname", res.data.username)
              this.$store.dispatch("setuserid", res.data.userid)
              //Vuex在用户刷新的时候userLogin会回到默认值false，所以我们需要用到HTML5储存
              //我们设置一个名为Flag，值为isLogin的字段，作用是如果Flag有值且为isLogin的时候，证明用户已经登录了。
              localStorage.setItem("Flag", "isLogin");
              localStorage.setItem("username", res.data.username);
              localStorage.setItem("userid", res.data.userid);
              this.$message.success(res.data.msg);
              this.$router.push("/home")
            } else {
              this.$message.error(res.data.msg)
            }
          })
        }
      });
    },
  },
}
</script>


