<template>
    <div id="liketop">
        <img class="liketopimg" src="../assets/img/looktop.png" alt>
        <div class="liketoplist">
            <ul>
                <li v-for="item in likelist" :key="item.id">
                    <router-link
                        tag="a"
                        :to="{ path: '/articledetail', query: { articleid: item.id }}"
                    >{{item.title}}</router-link>
                    <router-link tag="a" style="display: inline;" :to="{ name: 'user', params: { userid: item.userid }}">
                        <span>
                            <a-icon type="user"/>
                            {{item.username}}
                        </span>
                    </router-link>
                    <span>
                        <a-icon type="eye"/>
                        {{item.look}}
                    </span>
                    <span>
                        <a-icon type="like"/>
                        {{item.like}}
                    </span>
                </li>
            </ul>
        </div>
    </div>
</template>
<style lang="less" scoped>
.liketopimg {
    width: 100%;
    min-height: 50px;
    margin-bottom: 6px;
}
.liketoplist {
    width: 100%;
    ul li {
        list-style: none;
        padding: 10px;
        border-bottom: 1px solid #f0f0f0;

        a {
            display: block;
            font-size: 15px;
            line-height: 25px;
        }
        span {
            margin-right: 20px;
            color: #b4b4b4;
        }
    }
}
</style>
<script>
export default {
    data() {
        return {
            likelist: []
        };
    },
    mounted: function() {
        this.$ajax
            .get(this.baseurl + "findTop", {
                params: {
                    type: "look"
                }
            })
            .then(res => {
                if (res.status == 200 && res.data.code == 200) {
                    this.likelist = res.data.data;
                } else {
                    alert("加载失败！");
                }
            });
    }
};
</script>


