<template>
  <div id="app">
    <Header></Header>
    <!-- 加载中 -->
    <a-spin :spinning="this.$store.state.loadding"
            tip="加载中 ...">
      <a-icon slot="indicator"
              type="loading"
              style="font-size: 24px"
              spin />
      <router-view v-if="isRouterAlive"></router-view>
    </a-spin>
    <Foot></Foot>
  </div>
</template>

<script>
import Header from "./components/header.vue"
import Foot from "./components/footer.vue"
export default {
  name: 'app',
  provide () {
    return {
      reload: this.reload
    }
  },
  data () {
    return {
      isRouterAlive: true,
    }
  },
  components: {
    Header,
    Foot
  },
  methods: {
    reload () {
      this.isRouterAlive = false
      this.$nextTick(function () {
        this.isRouterAlive = true
      })
    }
  },
  created () {
    this.$notification.open({
      message: '欢迎来到杨利伟的博客',
      description: '欢迎您！'
    });
  }
}
</script>

<style>
* {
  padding: 0;
  margin: 0;
}
#app {
  padding-top: 58px;
}
a {
  color: #333;
}
</style>
