<template>
    <div id="comment">
        <h2 v-if="!comments.length" class="commenttitle">评论</h2>
        <div>
            <a-list v-if="comments.length" :dataSource="comments" itemLayout="horizontal">
                <h2 class="left" slot="header">{{comments.length}}条评论</h2>
                <a-list-item slot="renderItem" slot-scope="item">
                    <a-comment :author="item.username" :datetime="item.createtime">
                        <p class="left" slot="content">{{item.comment}}</p>
                    </a-comment>
                </a-list-item>
            </a-list>
            <a-comment v-if="!loginshow" >
                <div slot="content">
                    <a-form-item>
                        <a-textarea
                            placeholder="输入评论内容以评论"
                            :rows="5"
                            @change="handleChange"
                            :value="commentvalue"
                        ></a-textarea>
                    </a-form-item>
                    <a-form-item>
                        <a-button htmlType="submit" @click="handleSubmit" type="primary">发表评论</a-button>
                    </a-form-item>
                </div>
            </a-comment>
        </div>
        <div v-if="loginshow">
            <a-button @click="tologin" type="primary">登录以评论</a-button>
        </div>
    </div>
</template>
<style lang="less" scoped>
.commenttitle {
    text-align: left;
    margin: 30px 0px 10px 0px;
}
.left {
    text-align: left;
}
</style>
<script>
export default {
    data() {
        return {
            comments: [],
            commentvalue: "",
            loginshow: localStorage.getItem("Flag") == "isLogin" ? false : true
        };
    },
    mounted() {
        this.getcomment();
    },
    methods: {
        // 查询评论
        getcomment() {
            this.$ajax
                .get(this.baseurl + "comment", {
                    params: {
                        articleid: this.$route.query.articleid
                    }
                })
                .then(res => {
                    if (res.status == 200 && res.data.code == 200) {
                        this.comments = res.data.data;
                    } else {
                        this.$message.error(res.data.msg);
                    }
                });
        },
        tologin() {
            this.$router.push("/login");
        },
        handleSubmit() {
            // eslint-disable-next-line no-console
            console.log("内容：", this.commentvalue);
            this.$ajax
                .post(
                    this.baseurl + "addcomment",
                    this.$qs.stringify({
                        userid: localStorage.getItem("userid"),
                        comment: this.commentvalue,
                        articleid: this.$route.query.articleid
                    })
                )
                .then(res => {
                    if (res.status == 200 && res.data.code == 200) {
                        this.$message.success(res.data.msg);
                        this.commentvalue = "";
                        this.getcomment();
                    } else {
                        this.$message.error(res.data.msg);
                    }
                });
        },
        handleChange(e) {
            this.commentvalue = e.target.value;
        }
    }
};
</script>
