import Vue from 'vue'
import App from './App.vue'
// 引入路由
import router from "./router.js"
// axios
import axios from 'axios'
import qs from 'qs'
// vuex
import store from "./store.js"

// 编辑器的样式
import 'quill/dist/quill.core.css'
import 'quill/dist/quill.snow.css'
import 'quill/dist/quill.bubble.css'

// antd-design
import {
  Menu,
  Icon,
  Form,
  Input,
  Button,
  Modal,
  notification,
  Carousel,
  Row,
  Col,
  Dropdown,
  message,
  Select,
  Spin,
  Table,
  Popconfirm,
  Rate,
  Comment,
  List
} from "ant-design-vue"
Vue.use(Menu)
Vue.use(Icon)
Vue.use(Form)
Vue.use(Input)
Vue.use(Button)
Vue.use(Modal)
Vue.use(Carousel)
Vue.use(Row)
Vue.use(Col)
Vue.use(Dropdown)
Vue.use(Select)
Vue.use(Spin)
Vue.use(Table)
Vue.use(Popconfirm)
Vue.use(Rate);
Vue.use(Comment);
Vue.use(List);
Vue.config.productionTip = false
// 全局弹窗
Vue.prototype.$notification = notification;
Vue.prototype.$message = message;
// 全局axios
axios.defaults.timeout = 15000;
Vue.prototype.$ajax = axios;
Vue.prototype.$qs = qs;
// 全局基本路径
Vue.prototype.baseurl = "http://123.58.6.244:8080/tp5-blog/"
// Vue.prototype.baseurl = "http://localhost/tp5-blog/"
// 全局过滤html
Vue.prototype.dis = function (str) {
  str = str.replace(/<\/?[^>]*>/g, ''); //去除HTML tag
  str = str.replace(/[ | ]*\n/g, '\n'); //去除行尾空白
  str = str.replace(/\n[\s| | ]*\r/g, '\n'); //去除多余空行
  str = str.slice(0, 100) + "...";
  return str;
}
//定义一个请求拦截器
axios.interceptors.request.use(function (config) {
  store.state.loadding = true; //在请求发出之前进行一些操作
  return config
})
//定义一个响应拦截器
axios.interceptors.response.use(function (config) {
  store.state.loadding = false; //在这里对返回的数据进行处理
  return config
})

// router配置
router.beforeEach((to, from, next) => {
  //获取用户登录成功后储存的登录标志
  let getFlag = localStorage.getItem("Flag");
  let username = localStorage.getItem("username");
  let userid = localStorage.getItem("userid")
  // 如果是已经登陆状态
  if (getFlag === "isLogin") {
    // 如果已经登陆,设置strore登陆状态为true
    store.dispatch("setUser", true)
    store.dispatch("setname", username)
    store.dispatch("setuserid", userid)
    next();
  } else { //如果是未登录状态
    store.dispatch("setUser", false)
    store.dispatch("setname", "")
    store.dispatch("setuserid", null)
    // 判断是否需要登陆
    if (to.meta.needLogin == true) {
      router.push("/login");
    } else {
      next()
    }
  }
})

new Vue({
  router, // 注入到根实例中
  store,
  render: h => h(App),
}).$mount('#app')