<template>
  <div id="search">
    <h1>
      <a-icon type="search" /> 搜索</h1>
    <ArticleList :list="searchlist">
      <!-- <span slot="contenttitle">{{item.title}}</span> -->
    </ArticleList>
  </div>
</template>
<script>
import ArticleList from "../components/article.vue"
export default {
  data () {
    return {
      searchlist: []
    }
  },
  components: {
    ArticleList
  },
  mounted () {
    //获取get过来的值
    var searchText = this.$route.params.searchText;
    // console.log(searchText);
    this.$ajax.get(this.baseurl + "search", {
      params: {
        searchText: searchText
      }
    })
      .then((res) => {
        if (res.status == 200 && res.data.code == 200) {
          this.searchlist = res.data.data;
          // console.log(this.searchlist);
          if(this.searchlist.length==0){
            alert("没有搜索到数据!")
          }
        } else {
          alert("加载失败！")
        }
      })
  }
}
</script>

<style lang="less" scoped>
#search {
  max-width: 1200px;
  margin: 20px auto 0px auto;
}
</style>

