import Vue from 'vue'
import Vuex from 'vuex'

Vue.use(Vuex)

const store = new Vuex.Store({
  //状态
  state: {
    isLogin: false,
    username: "",
    userid: null,
    loadding: false
  },
  //状态修改方法
  // 使用store.commit()来调用
  mutations: {
    // userid
    useridstate(state, flag) {
      state.userid = flag
    },
    // 保存登陆状态
    userStatus(state, flag) {
      state.isLogin = flag
    },
    // username
    username(state, name) {
      state.username = name
    },
    // loadding
    showloadding(state, load) {
      state.loadding = load
    }
  },
  //调用mutations，可以包含异步操作
  // 可以用store.dispatch来调用
  actions: {
    // 使用mutations的方法
    setuserid(context, flag) {
      context.commit('useridstate', flag)
    },
    setUser(context, flag) {
      context.commit('userStatus', flag)
    },
    setname(context, name) {
      context.commit("username", name)
    },
    setloadding(context, load) {
      context.commit("showloadding", load);
    }
  },
  getters: {
    // 获取登陆状态
    isLogin: (state) => {
      return state.isLogin
    },
    isname: (state) => {
      return state.username
    },
    isloading: (state) => {
      return state.loadding
    },
    isuserid: (state) => {
      return state.userid
    }
  }
})
// 导出!!!!
export default store