<template>
  <div id="web">
    <div class="main">
      <a-row :gutter="24">
        <a-col :xs="{span:22,offset:1}"
               :lg="{span:16,offset:0}">
          <h1>
            <a-icon type="ie"  /> 前端</h1>
          <ArticleList :list="articlecontent">
            <!-- <span slot="contenttitle">{{item.title}}</span> -->
          </ArticleList>
          <a-button class="getmorebtn"
                    v-show="showgetmore"
                    v-if="articlecontent.length>9"
                    @click="getmore">加载更多</a-button>
        </a-col>
        <a-col :xs="0"
               :offset="1"
               :lg="7">
          <LikeTop></LikeTop>
          <LookTop></LookTop>
        </a-col>
      </a-row>
    </div>
  </div>
</template>
<style lang="less" scoped>
#web {
  max-width: 1200px;
  margin: 20px auto 0px auto;
}
.getmorebtn {
  margin: 0 auto;
  display: block;
}
</style>
<script>
import ArticleList from "../components/article.vue"
import LikeTop from "../components/liketop.vue"
import LookTop from "../components/looktop.vue"
export default {
  data () {
    return {
      page: 1,
      articlecontent: [],
      showgetmore: true
    }
  }, components: {
    ArticleList,
    LikeTop,
    LookTop
  },
  mounted () {
    // 获取数据
    this.$ajax.get(this.baseurl + "findAll", {
      params: {
        cateid: 1,
        page: 1
      }
    }).then((res) => {
      if (res.status == 200 && res.data.code == 200) {
        this.articlecontent = res.data.data.data;
      } else {
        alert("加载失败！")
      }
    })
  },
  methods: {
    changedefault: () => {
      this.$emit("change", "2")
    },
    getmore: function () {
      // console.log("获取更多")
      this.page++;
      this.$ajax.get(this.baseurl + "findAll", {
        params: {
          cateid: 1,
          page: this.page
        }
      })
        .then((res) => {
          if (res.status == 200 && res.data.code == 200 && res.data.data.data.length > 0) {
            var arr = this.articlecontent;
            for (var i in res.data.data.data) {
              arr.push(res.data.data.data[i])
            }
            this.articlecontent = arr;
          } else if (res.data.data.data.length <= 0) {
            this.$message.info("没有更多了！")
            this.showgetmore = false;
          } else {
            this.$message.error("加载失败！")
          }
        })
    }
  }
}
</script>
