<template>
    <div id="articledetail">
        <h1>{{articledetail.title}}</h1>
        <div>
            <router-link tag="a" :to="{ name: 'user', params: { userid: articledetail.userid }}">
                <span>
                    <a-icon type="user"/>
                    {{articledetail.username}}
                </span>
            </router-link>
            <span>
                <a-icon type="eye"/>
                {{articledetail.look}}
            </span>
            <span>
                <a-icon type="like"/>
                {{articledetail.like}}
            </span>
            <span>
                <a-icon type="clock-circle"/>
                {{articledetail.createtime}}
            </span>
        </div>
        <div class="content">
            <!-- {{articledetail.content}} -->
            <div class="ql-editor" v-html="articledetail.content"></div>
        </div>
        <span>
            <span>评分：{{rate>0?rate+"星":"无评分"}}</span>
            <a-rate @change="changerate" v-model="rateval">
                <!-- <span  slot="character">棒</span> -->
                <!-- <a-icon type="heart" slot="character" theme="twoTone" twoToneColor="#eb2f96" /> -->
                <!-- <a-icon slot="character" type="star" /> -->
            </a-rate>
        </span>
        <a-button class="likebtn" type="primary" size="large" @click="onlike">
            <a-icon type="like"/>
            点赞 {{articledetail.like}}
        </a-button>
        <comment></comment>
    </div>
</template>
<script>
import comment from "../components/comment.vue";
export default {
    data() {
        return {
            rate: null,
            // 评分
            rateval: null,
            articleid: "",
            articledetail: []
        };
    },
    components: {
        comment
    },
    mounted() {
        // console.log(this.$route.query)
        this.articleid = this.$route.query.articleid;
        this.getarticle();
    },
    methods: {
        // 获取文章内容
        getarticle() {
            this.$ajax
                .get(this.baseurl + "article", {
                    params: {
                        articleid: this.articleid
                    }
                })
                .then(res => {
                    // console.log(res)
                    if (res.status == 200 && res.data.code == 200) {
                        this.articledetail = res.data.data;
                        var a = parseInt(
                            res.data.data.rate / res.data.data.ratenum
                        );
                        this.rate = a;
                        this.rateval = a;
                    } else {
                        alert(res.data.msg);
                    }
                });
        },
        // 评分
        changerate(value) {
            if (localStorage.getItem("Flag") == "isLogin") {
                this.$ajax
                    .get(this.baseurl + "rate", {
                        params: {
                            rate: value,
                            userid: localStorage.getItem("userid"),
                            articleid: this.articleid
                        }
                    })
                    .then(res => {
                        if (res.status == 200 && res.data.code == 200) {
                            this.$message.success(res.data.msg);
                            this.getarticle();
                        } else {
                            this.$message.error(res.data.msg);
                        }
                    });
            } else {
                this.$notification.warning({
                    message: "请先登录！",
                    description: "如果要评分，必须要登录！",
                    duration: 2,
                    onClose: () => {
                        this.$router.push("/login");
                    }
                });
            }
        },
        // 点赞
        onlike: function() {
            if (localStorage.getItem("Flag") == "isLogin") {
                this.$ajax
                    .get(this.baseurl + "like", {
                        params: {
                            userid: localStorage.getItem("userid"),
                            articleid: this.articleid
                        }
                    })
                    .then(res => {
                        if (res.status == 200 && res.data.code == 200) {
                            this.getarticle();
                            this.$message.success(res.data.msg);
                        } else {
                            this.$message.error(res.data.msg);
                        }
                    });
            } else {
                this.$notification.warning({
                    message: "请先登录！",
                    description: "如果要点赞，必须要登录！",
                    duration: 2,
                    onClose: () => {
                        this.$router.push("/login");
                    }
                });
            }
        }
    }
};
</script>

<style lang="less" scoped>
#articledetail {
    max-width: 1200px;
    margin: 30px auto;
    text-align: center;
    h1 {
        font-weight: 700;
    }
    span {
        margin: 10px;
    }
    .content {
        margin: 20px 0px;
        min-height: 500px;
    }
}
.likebtn {
    background: #f5222d;
    border-color: #f5222d;
}
</style>

