<template>
    <div id="manager">
        <h1>
            <a-icon type="setting"/>
            {{this.$store.state.username}}的博客
        </h1>
        <a-button type="primary" :loading="loading" @click="dels" :disabled="!hasSelected">批量删除</a-button>
        <a-table
            class="table"
            :rowSelection="{selectedRowKeys: selectedRowKeys, onChange: onSelectChange}"
            :columns="columns"
            :pagination="pagination"
            :rowKey="record => record.id"
            :dataSource="data"
            @change="handleTableChange"
        >
            <!-- title重置 -->
            <span slot="title" slot-scope="text">
                <router-link
                    target="_blank"
                    :to="{ path: '/articledetail', query: { articleid: text.id }}"
                >{{text.title}}</router-link>
            </span>
            <!-- 操作重置 -->
            <div slot="action" slot-scope="text, record">
                <span style="margin-right:10px;">
                    <a-button size="small" @click="linktoedit(record.id)">修改</a-button>
                </span>
                <span>
                    <a-popconfirm
                        v-if="data.length"
                        title="确定删除吗?"
                        okText="删除"
                        cancelText="取消"
                        @confirm="() => onDelete(record.id)"
                    >
                        <a-icon slot="icon" type="question-circle-o" style="color: red"/>
                        <a-button type="danger" size="small">删除</a-button>
                    </a-popconfirm>
                </span>
            </div>
        </a-table>
    </div>
</template>
<script>
const columns = [
    {
        title: "博客ID",
        dataIndex: "id",
        key: "id"
    },
    {
        title: "标题",
        // dataIndex: 'title',
        key: "title",
        scopedSlots: { customRender: "title" }
    },
    {
        title: "分类",
        dataIndex: "category",
        key: "category"
    },
    {
        title: "点赞数",
        dataIndex: "like",
        key: "like"
    },
    {
        title: "浏览数",
        dataIndex: "look",
        key: "look"
    },
    {
        title: "发表时间",
        dataIndex: "createtime",
        key: "createtime"
    },
    {
        title: "操作",
        key: "action",
        scopedSlots: { customRender: "action" }
    }
];

export default {
    inject: ["reload"],
    data() {
        return {
            data: [],
            columns,
            selectedRowKeys: [], // Check here to configure the default column
            loading: false,
            pagination: {}
        };
    },
    computed: {
        hasSelected() {
            return this.selectedRowKeys.length > 0;
        }
    },
    mounted() {
        this.getdata();
    },
    methods: {
        // 导航到修改页面
        linktoedit(id) {
            this.$router.push({ path: `/edit/${id}` });
            // this.$router.push({ path: "/edit", params: { aritcleid: id } });
        },
        //表格发生变化的时候
        handleTableChange(pagination) {
            // eslint-disable-next-line no-console
            console.log(pagination);
            const pager = { ...this.pagination };
            pager.current = pagination.current;
            this.pagination = pager;
            this.getdata({
                page: pagination.current
            });
        },
        // 获取数据
        getdata: function(params = {}) {
            // eslint-disable-next-line no-console
            console.log("params:", params);
            this.$ajax({
                method: "post",
                url: this.baseurl + "userblog",
                params: {
                    userid: localStorage.getItem("userid"),
                    ...params
                }
            }).then(res => {
                // eslint-disable-next-line no-console
                console.log(res);
                if (res.status == 200 && res.data.code == 200) {
                    this.data = res.data.data.data;
                    const pagination = { ...this.pagination };
                    pagination.total = res.data.data.total;
                    this.pagination = pagination;
                } else {
                    alert("加载失败！");
                }
            });
        },
        onDelete: function(id) {
            this.$ajax({
                method: "post",
                url: this.baseurl + "blogdel",
                params: {
                    userid: localStorage.getItem("userid"),
                    blogid: id
                }
            }).then(res => {
                // console.log(res);
                if (res.status == 200 && res.data.code == 200) {
                    const dataSource = this.data;
                    this.data = dataSource.filter(function(item) {
                        return item.id !== id;
                    });
                    this.$message.success(res.data.msg);
                }
            });
        },
        dels() {
            if (confirm("确定删除么？")) {
                this.loading = true;
                this.$ajax({
                    method: "post",
                    url: this.baseurl + "blogdel",
                    params: {
                        userid: localStorage.getItem("userid"),
                        blogid: this.selectedRowKeys
                    }
                }).then(res => {
                    // console.log(res);
                    if (res.status == 200 && res.data.code == 200) {
                        this.$message.success(res.data.msg);
                        this.reload();
                    }
                });
            }
        },
        onSelectChange(selectedRowKeys) {
            // eslint-disable-next-line no-console
            console.log("selectedRowKeys changed: ", selectedRowKeys);
            this.selectedRowKeys = selectedRowKeys;
        }
    }
};
</script>
<style lang="less" scoped>
#manager {
    max-width: 1200px;
    margin: 20px auto 0px auto;
}
.table {
    margin-top: 20px;
}
</style>
