<template>
  <div id="write">
    <h1>
      <a-icon type="edit" /> 写博客</h1>
    <a-form :form="form"
            @submit="handleSubmit">
      <a-form-item v-bind="formItemLayout"
                   label="发表人：">
        <span class="ant-form-text">
          {{this.$store.state.username}}
        </span>
      </a-form-item>
      <a-form-item v-bind="formItemLayout"
                   label="文章标题："
                   has-feedback>
        <a-input size="large"
                 v-decorator="[
          'title',
          {
            rules: [{max:40,message:'最大四十个字符！'},{
              required: true, message: '必须填写标题!',
            }]
          }
        ]" />
      </a-form-item>
      <a-form-item v-bind="formItemLayout"
                   label="文章类别："
                   has-feedback>
        <a-select size="large"
                  v-decorator="[
          'categoryid',
          {rules: [{ required: true, message: '必须选择文章类别!' }]}
        ]"
                  placeholder="请选择文章类别">
          <a-select-option v-for="item in category"
                           :key="item.id"
                           :value="item.id">
            {{item.category}}
          </a-select-option>
        </a-select>
      </a-form-item>
      <a-form-item v-bind="formItemLayout"
                   label="文章内容："
                   has-feedback>
        <quillEditor :options="editorOption"
                     v-model="content"
                     ref="myQuillEditor"
                     @blur="onEditorBlur($event)"
                     @focus="onEditorFocus($event)"
                     @change="onEditorChange($event)"
                     required></quillEditor>
      </a-form-item>
      <a-form-item v-bind="tailFormItemLayout">
        <a-button size="large"
                  type="primary"
                  html-type="submit"
                  class="login-form-button">
          发表文章
        </a-button>
      </a-form-item>
    </a-form>
  </div>
</template>
<script>
import { quillEditor } from "vue-quill-editor"; //调用编辑器
import 'quill/dist/quill.core.css';
import 'quill/dist/quill.snow.css';
import 'quill/dist/quill.bubble.css';
export default {
  inject: ['reload'],
  data () {
    return {
      // Grid 栅格布局
      formItemLayout: {
        labelCol: {
          xs: { span: 24 },
          sm: { span: 4 },
        },
        wrapperCol: {
          xs: { span: 24 },
          sm: { span: 16 },
        },
      },
      tailFormItemLayout: {
        wrapperCol: {
          xs: {
            span: 24,
            offset: 0,
          },
          sm: {
            span: 16,
            offset: 4,
          },
        },
      },
      // 文章类别
      category: [],
      // 文章内容：
      content: "",
      editorOption: {
        placeholder: "请输入内容...",
        modules: {
          toolbar: [
            [
              { size: ["small", false, "large", "huge"] },
              { header: [1, 2, 3, 4, 5, 6, false] },
              { color: [] },
              {background:[]},
              { align: [] },
              "bold",
              "italic",
              "underline",
              "strike",
              "link",
              "blockquote",
              "code-block",
              "image",
              "video",
              "clean"
            ],
          ]
        }
      }
    }
  },
  components: {
    quillEditor
  },
  beforeCreate () {
    this.form = this.$form.createForm(this);
  },
  mounted () {
    // 获取类别
    this.$ajax.get(this.baseurl + "getcategory")
      .then((res) => {
        if (res.status == 200 && res.data.code == 200) {
          this.category = res.data.data;
        } else {
          this.$message.error("加载失败！")
        }
      })
  },
  methods: {
    handleSubmit (e) {
      e.preventDefault();
      this.form.validateFieldsAndScroll((err, values) => {
        if (!err) {
          if (this.content != "") {
            values.content = this.content;
            values.authorid = parseInt(localStorage.getItem("userid"));
            this.$ajax.post(this.baseurl + "Add", this.$qs.stringify(values))
              .then((res) => {
                if (res.status == 200 && res.data.count >= 1 && res.data.code == 200) {
                  this.$message.success(res.data.msg)
                  this.reload();
                } else {
                  this.$message.error(res.data.msg)
                }
              })
          } else {
            this.$message.error("必须填写内容！")
          }
        }
      });
    },
    onEditorBlur () {//失去焦点事件
    },
    onEditorFocus () {//获得焦点事件
    },
    onEditorChange ({ html }) {//改变内容事件
      this.content = html
    }
  },
  computed: {
    editor () {
      return this.$refs.myQuillEditor.quill
    }
  },
}

</script>
<style lang="less">
#write {
  max-width: 1200px;
  margin: 20px auto 0px auto;
}
.ql-toolbar.ql-snow {
  line-height: 20px;
  border-top-left-radius: 5px;
  border-top-right-radius: 5px;
}
.ql-container.ql-snow {
  border-bottom-left-radius: 5px;
  border-bottom-right-radius: 5px;
}
</style>


