<template>
    <div id="userblog">
        <div class="main">
            <a-row :gutter="24">
                <a-col :xs="{span:22,offset:1}" :lg="{span:16,offset:0}">
                    <h1 :style="{color:textcolor}">
                        <a-icon type="user"/>
                        {{ username? username.toUpperCase()+"的博客":"无内容"}}
                    </h1>
                    <ArticleList :list="articlecontent">
                        <!-- <span slot="contenttitle">{{item.title}}</span> -->
                    </ArticleList>
                    <a-button
                        class="getmorebtn"
                        v-show="showgetmore"
                        v-if="articlecontent.length>9"
                        @click="getmore"
                    >加载更多</a-button>
                </a-col>
                <a-col :xs="0" :offset="1" :lg="7">
                    <LikeTop></LikeTop>
                    <LookTop></LookTop>
                </a-col>
            </a-row>
        </div>
    </div>
</template>
<script>
import ArticleList from "../components/article.vue";
import LikeTop from "../components/liketop.vue";
import LookTop from "../components/looktop.vue";
export default {
    data() {
        return {
            textcolor: "pink",
            page: 1,
            articlecontent: [],
            showgetmore: true,
            userid: null,
            username: ""
        };
    },
    components: {
        ArticleList,
        LikeTop,
        LookTop
    },
    mounted() {
        this.changecolor();
        this.userid = this.$route.params.userid;
        // 获取数据
        this.$ajax({
            method: "post",
            url: this.baseurl + "userblog",
            params: {
                userid: this.userid
            }
        }).then(res => {
            if (res.status == 200 && res.data.code == 200) {
                this.articlecontent = res.data.data.data;
                this.username = res.data.data.data[0].username;
            } else {
                alert("加载失败！");
            }
        });
    },
    methods: {
        // 生成随机颜色
        changecolor() {
            //十六进制颜色随机
            var r = Math.floor(Math.random() * 256);
            var g = Math.floor(Math.random() * 256);
            var b = Math.floor(Math.random() * 256);
            var color = "#" + r.toString(16) + g.toString(16) + b.toString(16);
            this.textcolor = color;
        },
        changedefault: () => {
            this.$emit("change", "2");
        },
        getmore: function() {
            // console.log("获取更多")
            this.page++;
            this.$ajax({
            method: "post",
            url: this.baseurl + "userblog",
            params: {
                userid: this.userid,
                page:this.page
            }
        })
                .then(res => {
                    if (
                        res.status == 200 &&
                        res.data.code == 200 &&
                        res.data.data.data.length > 0
                    ) {
                        var arr = this.articlecontent;
                        for (var i in res.data.data.data) {
                            arr.push(res.data.data.data[i]);
                        }
                        this.articlecontent = arr;
                    } else if (res.data.data.data.length <= 0) {
                        this.$message.info("没有更多了！");
                        this.showgetmore = false;
                    } else {
                        this.$message.error("加载失败！");
                    }
                });
        }
    }
};
</script>
<style lang="less" scoped>
#userblog {
    max-width: 1200px;
    margin: 20px auto 0px auto;
}
.getmorebtn {
    margin: 0 auto;
    display: block;
}
</style>