<template>
  <div id="reg">
    <h1>
      <a-icon type="user" /> 注册新用户</h1>
    <a-form :form="form"
            @submit="handleSubmit">
      <a-form-item label="用户名："
                   v-bind="formItemLayout">
        <a-input v-decorator="['username',{rules: [{
              min:4,max:20,required: true,message:'必须填写用户名，且在4-20位之间！'},,{
              pattern:/^[0-9a-zA-Z]+$/,message: '只能包含数字或者英文!',}]}]" />
      </a-form-item>
      <a-form-item label="密码："
                   v-bind="formItemLayout">
        <a-input type="password"
                 v-decorator="[
          'password',
          {
            rules: [{
              min:6,max:20,required: true, message: '必须填写密码，且在6-20位之间！!'},{
              pattern:/^[0-9a-zA-Z]+$/,message: '只能包含数字或者英文!',}]
          }
        ]" />
      </a-form-item>
      <a-form-item label="确认密码："
                   v-bind="formItemLayout">
        <a-input type="password"
                 @blur="handleConfirmBlur"
                 v-decorator="[
          'confirm',
          {
            rules: [{
              required: true, message: '必须确认密码!'},{
              validator: compareToFirstPassword,
            }]
          }
        ]" />
      </a-form-item>
      <a-form-item v-bind="tailFormItemLayout">
        <a-button size="large"
                  type="primary"
                  html-type="submit"
                  class="login-form-button">
          注册用户
        </a-button>
      </a-form-item>
    </a-form>
  </div>
</template>
<script>
export default {
  inject: ['reload'],
  beforeCreate () {
    this.form = this.$form.createForm(this);
  },
  data () {
    return {
      // Grid 栅格布局
      formItemLayout: {
        labelCol: {
          xs: { span: 24 },
          sm: { span: 4 },
        },
        wrapperCol: {
          xs: { span: 24 },
          sm: { span: 16 },
        },
      },
      tailFormItemLayout: {
        wrapperCol: {
          xs: {
            span: 24,
            offset: 0,
          },
          sm: {
            span: 16,
            offset: 4,
          },
        },
      },
    }
  },
  methods: {
    handleSubmit (e) {
      e.preventDefault();
      this.form.validateFieldsAndScroll((err, values) => {
        if (!err) {
          if (this.content != "") {
            this.$ajax.post(this.baseurl + "reg", this.$qs.stringify(values))
              .then((res) => {
                if (res.status == 200 && res.data.code == 200) {
                  this.$message.success(res.data.msg)
                  this.reload();
                } else {
                  this.$message.error(res.data.msg)
                }
              })
          } else {
            this.$message.error("必须填写内容！");
          }
        }
      });
    },
    // 失去焦点就判断
    handleConfirmBlur (e) {
      const value = e.target.value;
      this.confirmDirty = this.confirmDirty || !!value;
    },
    // 判断两次密码是否一致
    compareToFirstPassword (rule, value, callback) {
      const form = this.form;
      if (value && value !== form.getFieldValue('password')) {
        callback('两次输入的密码不一致！');
      } else {
        callback();
      }
    },
  },
}
</script>
<style lang="less" scoped>
#reg {
  max-width: 1200px;
  margin: 20px auto 0px auto;
}
</style>


