<template>
    <div id="article">
        <div class="article" v-for="item in list" :key="item.id">
            <router-link
                class="title"
                :to="{ path: '/articledetail', query: { articleid: item.id }}"
            >{{item.title}}</router-link>
            <!-- <div class="content" v-html="item.content"> -->
            <div class="content">{{dis(item.content)}}</div>
            <div class="meta">
                <router-link :to="{ name: 'user', params: { userid: item.userid }}">
                    <span>
                        <a-icon type="user"/>
                        {{item.username}}
                    </span>
                </router-link>
                <span>
                    <a-icon type="eye"/>
                    {{item.look}}
                </span>
                <span>
                    <a-icon type="like"/>
                    {{item.like}}
                </span>
                <span>
                    <a-icon type="clock-circle"/>
                    {{item.createtime}}
                </span>
            </div>
        </div>
    </div>
</template>
<script>
export default {
    // 父组件传值过来
    props: {
        list: {
            type: Array
        }
    }
};
</script>

<style lang="less" scoped>
.article {
    margin: 0 0 15px;
    padding: 15px 2px 20px 0;
    border-bottom: 1px solid #f0f0f0;
    .title {
        font-size: 18px;
        font-weight: 700;
    }
    .content {
        margin: 0 0 8px;
        font-size: 13px;
        line-height: 30px;
        color: #999;
        max-height: 60px;
        overflow: hidden;
    }
    .meta {
        font-size: 12px;
        font-weight: 400;
        line-height: 20px;
        span {
            margin-right: 10px;
            color: #b4b4b4;
        }
    }
}
</style>

