<template>
  <div id="header">
    <div class="header-main">
      <img src="../assets/img/logo.png"
           class="header-logo"
           alt>
      <div class="header-mid">
        <a-menu mode="horizontal"
                :selectedKeys="[$route.path]"
                :style="{ lineHeight: '57px',borderBottom:'none' }">
          <a-menu-item key="/home">
            <router-link to="/home">
              <a-icon type="home" />首页
            </router-link>
          </a-menu-item>
          <a-menu-item key="/Web">
            <router-link to="/Web">
              <a-icon type="ie" />前端
            </router-link>
          </a-menu-item>
          <a-menu-item key="/back">
            <router-link to="/back">
              <a-icon type="api" />后端
            </router-link>
          </a-menu-item>
          <a-menu-item key="/other">
            <router-link to="/other">
              <a-icon type="pushpin" />其他
            </router-link>
          </a-menu-item>
        </a-menu>
      </div>
      <div class="search-form">
        <a-form layout="inline"
                :form="form"
                @submit="handleSubmit"
                :style="{paddingTop:'9px'}">
          <a-form-item>
            <a-input v-decorator="['searchText']"
                     placeholder="请输入搜索内容">
              <a-icon slot="prefix"
                      type="search"
                      style="color:rgba(0,0,0,.25)" />
            </a-input>
          </a-form-item>
          <a-form-item>
            <a-button type="primary"
                      html-type="submit">搜索</a-button>
          </a-form-item>
        </a-form>
      </div>

      <div class="header-right">
        <a-button type="primary">
          <router-link to="/write">
            <a-icon type="edit" />写博客
          </router-link>
        </a-button>
        <a-button type="primary"
                  ghost
                  v-show="this.$store.state.isLogin?false:true">
          <router-link to="/login">登陆</router-link>
        </a-button>
        <a-dropdown v-show="this.$store.state.isLogin">
          <a-menu slot="overlay">
            <a-menu-item key="0">
              <router-link tag="a"
                           :to="{ name: 'user', params: { userid: this.$store.state.userid }}">
                <a-icon type="user"
                        class="icon" />我的博客
              </router-link>
            </a-menu-item>
            <a-menu-item key="1">
              <router-link tag="a"
                           to="/manager">
                <a-icon type="setting"
                        class="icon" />管理博客
              </router-link>
            </a-menu-item>
            <a-menu-divider />
            <a-menu-item key="2"
                         @click="logout"
                         style="color:red">
              <a-icon type="logout" />退出登陆
            </a-menu-item>
          </a-menu>
          <a-button type="primary"
                    ghost
                    style="margin-left: 8px">
            {{this.$store.state.username}}
            <a-icon type="down" />
          </a-button>
        </a-dropdown>
      </div>
    </div>
  </div>
</template>
<script>
export default {
  inject: ["reload"],
  data () {
    return {
      form: this.$form.createForm(this)
    };
  },
  methods: {
    handleSubmit (e) {
      e.preventDefault();
      this.form.validateFields((err, values) => {
        if (!err) {
          if (values.searchText == undefined) {
            alert("请输入内容!");
          } else {
            // console.log(values)
            this.reload();
            this.$router.push({
              name: "search",
              params: { searchText: values.searchText }
            });
          }
        }
      });
    },
    logout: function () {
      this.$ajax.post(this.baseurl + "logout").then(res => {
        if (res.status == 200 && res.data.code == 200) {
          localStorage.setItem("Flag", "");
          localStorage.setItem("username", "");
          localStorage.setItem("userid", "");
          if (this.$route.name == "home") {
            location.reload();
          } else {
            this.$router.push("/home");
          }
        }
      });
    }
  }
};
</script>
<style lang="less" scoped>
#header {
  position: fixed;
  z-index: 999;
  top: 0px;
  width: 100%;
  background-color: white;
  border-bottom: 1px solid #ccc;
  .header-main {
    height: 58px;
    margin: 0 auto;
    display: flex;
    justify-content: space-around;
    .header-logo {
      width: 150px;
      height: 56px;
      display: block;
      float: left;
    }
    .header-mid {
      display: block;
      float: left;
    }
    .header-right {
      display: block;
      float: left;
      line-height: 58px;
      button {
        margin: 0 5px;
      }
    }
  }
}
.ant-menu-horizontal > .ant-menu-item {
  width: 100px;
}
.search-form {
  height: 58px;
  display: block;
  width: 300px;
  float: left;
}
@media (max-width: 1050px) {
  .search-form {
    display: none !important;
  }
  .header-mid {
    width: 400px;
  }
}
@media (max-width: 800px) {
  .header-right {
    display: none !important;
  }
  .header-mid {
    width: 400px;
  }
}
@media (max-width: 550px) {
  .header-logo {
    display: none !important;
  }
  .header-mid {
    width: 400px;
  }
}
@media (max-width: 400px) {
  .header-logo {
    display: none !important;
  }
  .header-mid {
    width: 100%;
  }
  .ant-menu-horizontal > .ant-menu-item {
    width: 25%;
  }
}
.icon {
  min-width: 12px;
  margin-right: 8px;
}
</style>


