import Vue from "vue";
import VueRouter from "vue-router";

import home from "./view/home.vue";
import web from "./view/web.vue";
import back from "./view/back.vue"
import other from "./view/other.vue"
import articledetail from "./view/articleDetail.vue"
import login from "./view/login.vue"
import write from "./view/write.vue"
import search from "./view/search.vue"
import reg from "./view/reg.vue"
import manager from "./view/manager.vue"
import edit from "./view/edit.vue"
import user from "./view/userblog.vue"
// 要告诉 vue 使用 vueRouter
Vue.use(VueRouter);

const routes = [{
    name: "index",
    path: "/",
    redirect: '/home'
  },
  {
    name: "home",
    path: "/home",
    component: home
  },
  {
    name: "web",
    path: "/web",
    component: web
  },
  {
    name: "back",
    path: "/back",
    component: back
  },
  {
    name: "other",
    path: "/other",
    component: other
  },
  {
    name: "articledetail",
    path: "/articledetail",
    component: articledetail
  },
  {
    name: "login",
    path: "/login",
    component: login
  },
  {
    name: "write",
    path: "/write",
    component: write,
    meta: {
      needLogin: true
    }
  }, {
    name: "search",
    path: "/search/:searchText",
    component: search
  }, {
    name: "reg",
    path: "/reg",
    component: reg
  }, {
    name: "manager",
    path: "/manager",
    component: manager,
    meta: {
      needLogin: true
    }
  },
  {
    name: "edit",
    path: "/edit/:articleid",
    component: edit
  }, {
    name: "user",
    path: "/user/:userid",
    component: user
  }
]

// 声明vuerouter并使用配置
var router = new VueRouter({
  routes
})

export default router;