<template>
  <div id="home">
    <div class="carousel">
      <carousel></carousel>
    </div>
    <div class="main">
      <a-row :gutter="24">
        <a-col :xs="{span:22,offset:1}"
               :lg="{span:16,offset:0}">
          <ArticleList :list="articlecontent">
          </ArticleList>
          <a-button class="getmorebtn"
                    v-show="showgetmore"
                    v-if="articlecontent.length>9"
                    @click="getmore">加载更多</a-button>
        </a-col>
        <a-col :xs="0"
               :offset="1"
               :lg="7">
          <LikeTop></LikeTop>
          <LookTop></LookTop>
        </a-col>
      </a-row>
    </div>

  </div>
</template>
<script>
import carousel from "../components/carousel.vue"
import ArticleList from "../components/article.vue"
import LikeTop from "../components/liketop.vue"
import LookTop from "../components/looktop.vue"
export default {
  data () {
    return {
      page: 1,
      articlecontent: [],
      showgetmore: true
    }
  }, components: {
    carousel,
    ArticleList,
    LikeTop,
    LookTop
  },
  mounted () {
    this.$ajax.get(this.baseurl + "findAll", {
      params: {
        page: this.page
      }
    }).then((res) => {
      if (res.status == 200 && res.data.code == 200) {
        this.articlecontent = res.data.data.data;
      } else {
        alert("加载失败！")
      }
    })
  },
  methods: {
    getmore: function () {
      // console.log("获取更多")
      this.page++;
      this.$ajax.get(this.baseurl + "findAll", {
        params: {
          page: this.page
        }
      })
        .then((res) => {
          if (res.status == 200 && res.data.code == 200 && res.data.data.data.length > 0) {
            var arr = this.articlecontent;
            for (var i in res.data.data.data) {
              arr.push(res.data.data.data[i])
            }
            this.articlecontent = arr;
          } else if (res.data.data.data.length <= 0) {
            this.$message.info("没有更多了！")
            this.showgetmore = false;
          } else {
            this.$message.error("加载失败！")
          }
        })
    }
  }
}
</script>
<style lang="less" scoped>
#home {
  max-width: 1200px;
  margin: 0 auto;
}
.carousel {
  margin-top: 20px;
  overflow: hidden;
}
.main {
  margin-top: 20px;
}
@media (max-width: 1200px) {
  .carousel {
    width: 96%;
    margin:20px auto;
  }
}
.getmorebtn {
  margin: 0 auto;
  display: block;
}
</style>


